#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_CLEAR_THRESHOLD_NTU 35
#define CONTROLLER_SETTLING_RESET_THRESHOLD_NTU 40
#define CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU 50
#define CONTROLLER_MIN_PROCESS_LEVEL 40
#define CONTROLLER_COMPLETE_LEVEL 15
#define CONTROLLER_CLEAR_STREAK_REQUIRED 3
#define CONTROLLER_SETTLING_MS 400U
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TURBIDITY,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TURBIDITY,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_IDLE = 0,
    CONTROLLER_STATE_FILTERING,
    CONTROLLER_STATE_SETTLING,
    CONTROLLER_STATE_DRAINING,
    CONTROLLER_STATE_COMPLETE,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int turbidity_ntu;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool filter_on;
    bool drain_open;
    controller_state_t state;
    bool has_valid_turbidity;
    int last_turbidity_ntu;
    uint32_t last_turbidity_ms;
    bool has_valid_level;
    int last_level;
    uint32_t last_level_ms;
    int clear_streak_count;
    uint32_t settling_started_ms;
} controller_t;

typedef struct {
    bool filter_on;
    bool drain_open;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* TODO: implement the filtering, settling, and draining state machine here. */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

#include "uart_transport.h"

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "controller.h"
#include "driver/uart.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "protocol.h"

#define UART_TRANSPORT_PORT UART_NUM_0
#define UART_TRANSPORT_BAUDRATE 115200
#define UART_TRANSPORT_BUFFER_SIZE 256
#define UART_TRANSPORT_LINE_BUFFER_SIZE 128
#define UART_TRANSPORT_HEARTBEAT_MS 1000U
#define UART_TRANSPORT_POLL_MS 50U

typedef struct {
    controller_t controller;
    char rx_line[UART_TRANSPORT_LINE_BUFFER_SIZE];
    size_t rx_line_length;
} uart_transport_context_t;

static uart_transport_context_t s_transport_context;

static uint32_t transport_now_ms(void)
{
    return (uint32_t) (xTaskGetTickCount() * portTICK_PERIOD_MS);
}

static void transport_send_line(const char *line)
{
    if (line == NULL) {
        return;
    }

    uart_write_bytes(UART_TRANSPORT_PORT, line, strlen(line));
}

static void transport_send_debug(const char *message)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    if (protocol_serialize_debug(message, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
}

static void transport_send_actuators(bool filter_on, bool drain_open)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    if (protocol_serialize_act_filter(filter_on, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
    if (protocol_serialize_act_drain(drain_open, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
}

static void transport_apply_protocol_input(const protocol_input_t *protocol_input)
{
    controller_input_t controller_input = {
        .kind = CONTROLLER_INPUT_NONE,
        .turbidity_ntu = 0,
        .level = 0,
        .now_ms = transport_now_ms(),
    };

    if (protocol_input == NULL) {
        return;
    }

    switch (protocol_input->kind) {
    case PROTOCOL_INPUT_TURBIDITY:
        controller_input.kind = CONTROLLER_INPUT_TURBIDITY;
        controller_input.turbidity_ntu = protocol_input->turbidity_ntu;
        break;
    case PROTOCOL_INPUT_LEVEL:
        controller_input.kind = CONTROLLER_INPUT_LEVEL;
        controller_input.level = protocol_input->level;
        break;
    case PROTOCOL_INPUT_SENSOR_TIMEOUT:
        controller_input.kind = CONTROLLER_INPUT_SENSOR_TIMEOUT;
        break;
    case PROTOCOL_INPUT_INVALID_TURBIDITY:
        controller_input.kind = CONTROLLER_INPUT_INVALID_TURBIDITY;
        break;
    case PROTOCOL_INPUT_INVALID_LEVEL:
        controller_input.kind = CONTROLLER_INPUT_INVALID_LEVEL;
        break;
    case PROTOCOL_INPUT_NONE:
    default:
        controller_input.kind = CONTROLLER_INPUT_NONE;
        break;
    }

    controller_output_t output = controller_step(&s_transport_context.controller, controller_input);
    if (output.changed || controller_input.kind != CONTROLLER_INPUT_NONE) {
        transport_send_actuators(output.filter_on, output.drain_open);
        transport_send_debug(output.state_name);
    }
}

static void transport_handle_received_line(const char *line)
{
    protocol_input_t input = {
        .kind = PROTOCOL_INPUT_NONE,
        .turbidity_ntu = 0,
        .level = 0,
    };

    protocol_parse_result_t result = protocol_parse_line(line, &input);
    if (result == PROTOCOL_PARSE_IGNORED) {
        return;
    }

    transport_apply_protocol_input(&input);
}

static void transport_poll_controller_timeout(void)
{
    controller_input_t controller_input = {
        .kind = CONTROLLER_INPUT_NONE,
        .turbidity_ntu = 0,
        .level = 0,
        .now_ms = transport_now_ms(),
    };

    controller_output_t output = controller_step(&s_transport_context.controller, controller_input);
    if (output.changed) {
        transport_send_actuators(output.filter_on, output.drain_open);
        transport_send_debug(output.state_name);
    }
}

static void transport_consume_uart_bytes(const uint8_t *bytes, size_t length)
{
    size_t index = 0;

    while (index < length) {
        const char current = (char) bytes[index++];
        if (current == '\r') {
            continue;
        }

        if (current == '\n') {
            s_transport_context.rx_line[s_transport_context.rx_line_length] = '\0';
            if (s_transport_context.rx_line_length > 0U) {
                transport_handle_received_line(s_transport_context.rx_line);
            }
            s_transport_context.rx_line_length = 0U;
            continue;
        }

        if (s_transport_context.rx_line_length + 1U < sizeof(s_transport_context.rx_line)) {
            s_transport_context.rx_line[s_transport_context.rx_line_length++] = current;
        } else {
            s_transport_context.rx_line_length = 0U;
            transport_send_debug("RX_LINE_TOO_LONG");
        }
    }
}

static void transport_task(void *unused)
{
    uint8_t buffer[UART_TRANSPORT_BUFFER_SIZE];
    uint32_t next_heartbeat_ms;

    (void) unused;

    transport_send_debug("BOOTED");
    transport_send_actuators(false, false);
    transport_send_debug("STATE SAFE_IDLE");
    next_heartbeat_ms = transport_now_ms() + UART_TRANSPORT_HEARTBEAT_MS;

    while (true) {
        const int bytes_read = uart_read_bytes(
            UART_TRANSPORT_PORT,
            buffer,
            sizeof(buffer),
            pdMS_TO_TICKS(UART_TRANSPORT_POLL_MS)
        );

        if (bytes_read > 0) {
            transport_consume_uart_bytes(buffer, (size_t) bytes_read);
        }

        transport_poll_controller_timeout();

        if (transport_now_ms() < next_heartbeat_ms) {
            continue;
        }

        transport_send_debug("HEARTBEAT");
        next_heartbeat_ms = transport_now_ms() + UART_TRANSPORT_HEARTBEAT_MS;
    }
}

void uart_transport_start(void)
{
    controller_init(&s_transport_context.controller);
    s_transport_context.rx_line_length = 0U;

    uart_config_t config = {
        .baud_rate = UART_TRANSPORT_BAUDRATE,
        .data_bits = UART_DATA_8_BITS,
        .parity = UART_PARITY_DISABLE,
        .stop_bits = UART_STOP_BITS_1,
        .flow_ctrl = UART_HW_FLOWCTRL_DISABLE,
        .source_clk = UART_SCLK_APB,
    };

    uart_driver_install(UART_TRANSPORT_PORT, UART_TRANSPORT_BUFFER_SIZE * 2, 0, 0, NULL, 0);
    uart_param_config(UART_TRANSPORT_PORT, &config);
    uart_set_pin(UART_TRANSPORT_PORT, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE);

    xTaskCreate(transport_task, "uart_transport", 4096, NULL, 5, NULL);
}

#ifndef PROTOCOL_H
#define PROTOCOL_H

#include <stdbool.h>
#include <stddef.h>

#define PROTOCOL_MAX_LINE_LENGTH 128

