    }
    return (now_ms - last_seen_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static bool is_sensor_valid(controller_t *controller, controller_input_t input)
{
    if (input.kind != CONTROLLER_INPUT_NONE) {
        return true;
    }
    // Check if sensor is stale (not seen within 1000ms)
    if (is_sensor_stale(input.now_ms, controller->last_turbidity_ms)) {
        return false;
    }
    if (is_sensor_stale(input.now_ms, controller->last_level_ms)) {
        return false;
    }
    return true;
}

static bool should_go_to_safe_idle(controller_t *controller)
{
    // If either sensor is stale, go to safe all-off
    if (is_sensor_stale(controller->last_turbidity_ms, 0U)) {
        return true;
    }
    if (is_sensor_stale(controller->last_level_ms, 0U)) {
        return true;
    }
    return false;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_filter_on = controller->filter_on;
    bool previous_drain_open = controller->drain_open;
    controller_state_t previous_state = controller->state;

    /* Check for malformed input or timeout */
    if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Handle sensor timeout - go to safe all-off */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Update sensor state based on input kind */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    default:
        /* No new sensor data */
        break;
    }

    /* Check if we should go to safe idle due to stale sensors */
    if (should_go_to_safe_idle(controller)) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Now process state machine based on current level and turbidity */
    bool filter_on = false;
    bool drain_open = false;
    controller_state_t state = CONTROLLER_STATE_SAFE_IDLE;
    bool changed = false;

    /* Check for COMPLETE state - level below threshold */
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        state = CONTROLLER_STATE_COMPLETE;
        filter_on = false;
        drain_open = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        changed = true;
    } else if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        /* Level is sufficient for processing */

        /* If we haven't seen valid turbidity yet, stay in SAFE_IDLE */
        if (!controller->has_valid_turbidity || !controller->has_valid_level) {
            state = CONTROLLER_STATE_SAFE_IDLE;
            filter_on = false;
            drain_open = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            changed = true;
        } else {
            /* Both sensors are valid - process based on turbidity */

            /* Check for high turbidity in filtering state */
            if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller->clear_streak_count = 0;
            }

            /* FILITERING state: TURB > 35 and LEVEL >= 40 */
            if (controller->state == CONTROLLER_STATE_FILTERING &&
                controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                filter_on = true;
                drain_open = false;
                changed = true;
            } else {
                /* Not filtering - check for SETTLING transition */

                /* Count clear streak if turbidity is good */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }

                /* Enter SETTLING after 3 consecutive clear readings with LEVEL >= 40 */
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    state = CONTROLLER_STATE_SETTLING;
                    filter_on = false;
                    drain_open = false;
                    changed = true;

                    /* Record when settling started */
                    if (controller->state != CONTROLLER_STATE_SETTLING) {
                        controller->settling_started_ms = input.now_ms;
                    }
                } else {
                    /* Stay in SAFE_IDLE or continue filtering based on turbidity */
                    state = CONTROLLER_STATE_SAFE_IDLE;
                    filter_on = false;
                    drain_open = false;
                    changed = true;
                }
            }

            /* Check for disturbance during SETTLING - return to FILTERING */
            if (state == CONTROLLER_STATE_SETTLING && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                state = CONTROLLER_STATE_FILTERING;
                filter_on = true;
                drain_open = false;
                controller->clear_streak_count = 0;
                changed = true;
            }

            /* Check for drain transition during SETTLING */
            if (state == CONTROLLER_STATE_SETTLING) {
                bool settling_elapsed = (input.now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS;
                bool latest_clear = controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU;

                if (settling_elapsed && latest_clear && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    state = CONTROLLER_STATE_DRAINING;
                    filter_on = false;
                    drain_open = true;
                    changed = true;
                }
            }

            /* Check for disturbance during DRAINING - return to FILTERING */
            if (state == CONTROLLER_STATE_DRAINING && controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
                state = CONTROLLER_STATE_FILTERING;
                filter_on = true;
                drain_open = false;
                controller->clear_streak_count = 0;
                changed = true;
            }

            /* Check if we should be filtering based on turbidity */
            if (controller->state == CONTROLLER_STATE_SAFE_IDLE &&
                controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                state = CONTROLLER_STATE_FILTERING;
                filter_on = true;
                drain_open = false;
                changed = true;
            }
        }
    }

    /* Update output */
    output.filter_on = filter_on;
    output.drain_open = drain_open;
    output.state = state;
    output.state_name = controller_state_name(state);
    output.changed = (previous_filter_on != filter_on) ||
                     (previous_drain_open != drain_open) ||
                     (previous_state != state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}
